+    fn test_is_night_at_equator_noon() {
+        // Noon UTC at equator on March 20 — should be daytime.
+        let dt = chrono::NaiveDate::from_ymd_opt(2025, 3, 20)
+            .unwrap()
+            .and_hms_opt(12, 0, 0)
+            .unwrap()
+            .and_utc();
